/**
 * Converts a number to a human-readable string with K suffix for thousands
 * @example 1500 -> "1.5K", 1000000 -> "1000000"
 */
function humanizeNumber(num: number): string {
  if (num < 1000) {
    return num.toString();
  }

  if (num < 100000) {
    // For numbers between 1,000 and 99,999, show with one decimal (e.g., 1.5K)
    const value = (num / 1000).toFixed(1);
    // Remove trailing .0 if present
    const formattedValue = value.endsWith('.0') ? value.slice(0, -2) : value;

    return `${formattedValue}K`;
  }

  if (num < 1000000) {
    // For numbers between 10,000 and 999,999, show as whole K (e.g., 10K, 999K)
    return `${Math.floor(num / 1000)}K`;
  }

  // For 1,000,000 and above, just return the number
  return num.toString();
}

"use client"

import { useEffect, useState, useCallback } from "react"
import { useRouter } from "next/navigation"
import { Command } from "cmdk"
import {
    IconFileText,
    IconBrandGithub,
    IconRocket,
    IconHome,
    IconSearch,
    IconTerminal,
} from "@tabler/icons-react"
import * as Dialog from "@radix-ui/react-dialog"
import type { PostWithMeta } from "@/lib/blog"
import type { Project } from "@/lib/projects"
import type { MiniApp } from "@/lib/mini-apps"

interface CommandMenuProps {
    posts: PostWithMeta[]
    projects: Project[]
    miniApps: MiniApp[]
}

export function CommandMenu({ posts, projects, miniApps }: CommandMenuProps) {
    const [open, setOpen] = useState(false)
    const router = useRouter()

    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
                e.preventDefault()
                setOpen((open) => !open)
            }
        }
        document.addEventListener("keydown", down)
        return () => document.removeEventListener("keydown", down)
    }, [])

    const runAction = useCallback(
        (action: () => void) => {
            setOpen(false)
            action()
        },
        []
    )

    return (
        <Command.Dialog open={open} onOpenChange={setOpen} label="Search">
            <Dialog.Title className="sr-only">Search</Dialog.Title>
            <Command.Input placeholder="Search..." />
            <Command.List>
                <Command.Empty>No results found.</Command.Empty>

                <Command.Group heading="Pages">
                    <Command.Item
                        value="home"
                        onSelect={() => runAction(() => router.push("/"))}
                    >
                        <IconHome className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Home</span>
                    </Command.Item>
                    <Command.Item
                        value="blog"
                        onSelect={() => runAction(() => router.push("/blog"))}
                    >
                        <IconFileText className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Blog</span>
                    </Command.Item>
                    <Command.Item
                        value="mini apps"
                        onSelect={() => runAction(() => router.push("/mini-apps"))}
                    >
                        <IconTerminal className="h-4 w-4 shrink-0 text-muted-foreground" />
                        <span>Mini Apps</span>
                    </Command.Item>
                </Command.Group>

                <Command.Separator />

                <Command.Group heading="Blog Posts">
                    {posts.map((post) => (
                        <Command.Item
                            key={post.slug}
                            value={`blog-${post.slug}`}
                            keywords={post.frontmatter.tags}
                            onSelect={() =>
                                runAction(() => router.push(`/blog/${post.slug}`))
                            }
                        >
                            <IconFileText className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex min-w-0 flex-col">
                                <span className="truncate">{post.frontmatter.title}</span>
                                {post.frontmatter.description && (
                                    <span className="truncate text-xs text-muted-foreground">
                                        {post.frontmatter.description}
                                    </span>
                                )}
                            </div>
                        </Command.Item>
                    ))}
                </Command.Group>

                <Command.Separator />

                <Command.Group heading="Projects">
                    {projects.map((project) => (
                        <Command.Item
                            key={project.title}
                            value={`project-${project.title}`}
                            onSelect={() => runAction(() => window.open(project.href, "_blank"))}
                        >
                            <IconBrandGithub className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex min-w-0 flex-col">
                                <span className="truncate">{project.title}</span>
                                <span className="truncate text-xs text-muted-foreground">
                                    {project.description}
                                </span>
                            </div>
                        </Command.Item>
                    ))}
                </Command.Group>

                <Command.Separator />

                <Command.Group heading="Mini Apps">
                    {miniApps.map((app) => (
                        <Command.Item
                            key={app.title}
                            value={`mini-${app.title}`}
                            onSelect={() =>
                                runAction(() => {
                                    const url = app.live || app.code
                                    if (url) window.open(url, "_blank")
                                })
                            }
                        >
                            <IconRocket className="h-4 w-4 shrink-0 text-muted-foreground" />
                            <div className="flex min-w-0 flex-col">
                                <span className="truncate">{app.title}</span>
                                <span className="truncate text-xs text-muted-foreground">
                                    {app.description}
                                </span>
                            </div>
                        </Command.Item>
                    ))}
                </Command.Group>
            </Command.List>
        </Command.Dialog>
    )
}

